import React, { useState, useEffect, useCallback } from 'react';
import { noticeAPI } from '../services/api';
import toast from 'react-hot-toast';

const TYPES = ['general','circular','event','holiday','urgent'];
const TYPE_COLOR = { general:['#F3F4F6','#374151'], circular:['#DBEAFE','#1E40AF'], event:['#EDE9F8','#5B21B6'], holiday:['#D1FAE5','#065F46'], urgent:['#FEE2E2','#991B1B'] };
const inp = { width:'100%', padding:'10px 12px', border:'1.5px solid #E5E7EB', borderRadius:9, fontSize:13, outline:'none', fontFamily:'inherit', background:'#fff', boxSizing:'border-box' };
const lbl = { display:'block', fontSize:11, fontWeight:700, color:'#4B5563', textTransform:'uppercase', letterSpacing:'.06em', marginBottom:6 };
const MOCK = [
  { id:1, title:'Parent-Teacher Meeting on 12 June 2025', notice_type:'event',    publish_date:'2025-06-05', content:'PTM scheduled for all classes.' },
  { id:2, title:'Half-Yearly Exam Schedule Released',     notice_type:'circular', publish_date:'2025-06-03', content:'Exams start from 20th June.' },
  { id:3, title:'Annual Day Preparations Begin',          notice_type:'event',    publish_date:'2025-06-01', content:'Students to report in costume.' },
  { id:4, title:'School Closed on 15 June — Eid Holiday', notice_type:'holiday', publish_date:'2025-06-07', content:'School will remain closed.' },
];

export default function Notices() {
  const [notices,  setNotices]  = useState([]);
  const [loading,  setLoading]  = useState(true);
  const [isMock,   setIsMock]   = useState(false);
  const [showAdd,  setShowAdd]  = useState(false);
  const [saving,   setSaving]   = useState(false);
  const [form, setForm] = useState({ title:'', content:'', type:'general' });

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await noticeAPI.getAll({ limit:50 });
      setNotices(res.data.data||[]); setIsMock(false);
    } catch { setNotices(MOCK); setIsMock(true); }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { load(); }, [load]);

  const handleAdd = async (e) => {
    e.preventDefault(); setSaving(true);
    try {
      await noticeAPI.create({ title:form.title, content:form.content, noticeType:form.type });
      toast.success('✅ Notice published to database!');
      setShowAdd(false); setForm({ title:'', content:'', type:'general' }); load();
    } catch {
      const mock = { id:Date.now(), title:form.title, notice_type:form.type, publish_date:new Date().toISOString().split('T')[0], content:form.content };
      setNotices(p=>[mock,...p]); toast.success('Notice published (demo mode)'); setShowAdd(false); setIsMock(true);
    } finally { setSaving(false); }
  };

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:20}}>
        <div>
          <h2 style={{fontSize:20,fontWeight:700,color:'#111827'}}>Notice Board</h2>
          <p style={{fontSize:12,color:'#6B7280',marginTop:2}}>
            {notices.length} notices
            {isMock ? <span style={{marginLeft:8,padding:'2px 8px',background:'#FEF3C7',color:'#92400E',borderRadius:10,fontSize:10,fontWeight:700}}>Demo mode</span>
                    : <span style={{marginLeft:8,padding:'2px 8px',background:'#D1FAE5',color:'#065F46',borderRadius:10,fontSize:10,fontWeight:700}}>🟢 Live DB</span>}
          </p>
        </div>
        <button onClick={()=>setShowAdd(true)} style={{padding:'9px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>📢 Post Notice</button>
      </div>

      {loading&&<div style={{padding:36,textAlign:'center',color:'#9CA3AF'}}>⏳ Loading…</div>}

      <div style={{display:'flex',flexDirection:'column',gap:12}}>
        {!loading&&notices.map((n,i)=>{
          const [bg,c] = TYPE_COLOR[n.notice_type]||TYPE_COLOR.general;
          return (
            <div key={n.id||i} style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:12,padding:'16px 18px',display:'flex',alignItems:'flex-start',gap:12,transition:'all .15s'}}
              onMouseEnter={e=>e.currentTarget.style.boxShadow='0 4px 12px rgba(0,0,0,.08)'}
              onMouseLeave={e=>e.currentTarget.style.boxShadow=''}>
              <span style={{padding:'3px 10px',borderRadius:20,fontSize:10,fontWeight:700,background:bg,color:c,flexShrink:0,marginTop:2,textTransform:'uppercase'}}>{n.notice_type}</span>
              <div style={{flex:1}}>
                <div style={{fontSize:13,fontWeight:700,color:'#111827'}}>{n.title}</div>
                {n.content&&<div style={{fontSize:11,color:'#6B7280',marginTop:3}}>{n.content}</div>}
                <div style={{fontSize:10,color:'#9CA3AF',marginTop:5}}>
                  {n.published_by||n.created_by||'Admin'} · {(n.publish_date||n.created_at||'').split('T')[0]}
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {showAdd&&(
        <div style={{position:'fixed',inset:0,background:'rgba(15,23,42,.45)',zIndex:400,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:18,width:500,overflow:'hidden'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <div style={{fontWeight:700,fontSize:15}}>📢 Post New Notice</div>
              <button onClick={()=>setShowAdd(false)} style={{background:'#F3F4F6',border:'none',borderRadius:8,width:32,height:32,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            <form onSubmit={handleAdd} style={{padding:20}}>
              <div style={{marginBottom:12}}><label style={lbl}>Title *</label><input required value={form.title} onChange={e=>setForm({...form,title:e.target.value})} placeholder="Notice title…" style={inp} autoFocus/></div>
              <div style={{marginBottom:12}}><label style={lbl}>Type</label><select value={form.type} onChange={e=>setForm({...form,type:e.target.value})} style={inp}>{TYPES.map(t=><option key={t}>{t}</option>)}</select></div>
              <div style={{marginBottom:16}}><label style={lbl}>Content *</label><textarea required value={form.content} onChange={e=>setForm({...form,content:e.target.value})} rows={4} placeholder="Notice content…" style={{...inp,resize:'vertical'}}/></div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                <button type="button" onClick={()=>setShowAdd(false)} style={{padding:'10px 16px',border:'1.5px solid #E5E7EB',borderRadius:9,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button type="submit" disabled={saving} style={{padding:'10px 22px',background:saving?'#9CA3AF':'#1E1B4B',color:'#fff',border:'none',borderRadius:9,fontSize:13,fontWeight:700,cursor:'pointer'}}>{saving?'⏳ Saving…':'📢 Publish'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
